# roles.py — Role and permission definitions
from dataclasses import dataclass, field
from typing import FrozenSet

@dataclass(frozen=True)
class Role:
    name: str
    permissions: FrozenSet[str]  # set of "resource:action" strings

ROLES: dict[str, Role] = {
    "researcher": Role(
        name="researcher",
        permissions=frozenset({
            "web:search",
            "docs:read",
            "knowledge_base:read",
        }),
    ),
    "writer": Role(
        name="writer",
        permissions=frozenset({
            "web:search",
            "docs:read",
            "docs:write",
            "knowledge_base:read",
        }),
    ),
    "code-executor": Role(
        name="code-executor",
        permissions=frozenset({
            "docs:read",
            "code:execute",
            "code:read",
        }),
    ),
    "ops": Role(
        name="ops",
        permissions=frozenset({
            "docs:read",
            "code:execute",
            "infra:deploy",
            "infra:read",
        }),
    ),
}

def get_permissions(role_name: str) -> FrozenSet[str]:
    role = ROLES.get(role_name)
    if role is None:
        raise ValueError(f"Unknown role: {role_name!r}")
    return role.permissions

# pep.py — Policy Enforcement Point as a decorator
import functools
from pdp import check_permission, PermissionDenied

def requires_permission(permission: str):
    """Decorator that enforces a specific permission before a tool is called."""
    def decorator(fn):
        @functools.wraps(fn)
        def wrapper(agent_ctx, *args, **kwargs):
            check_permission(
                agent_id=agent_ctx.agent_id,
                role_name=agent_ctx.role,
                permission=permission,
            )
            return fn(agent_ctx, *args, **kwargs)
        return wrapper
    return decorator


# --- Tool definitions using the decorator ---

@requires_permission("web:search")
def tool_web_search(agent_ctx, query: str) -> list[dict]:
    """Perform a web search. Only agents with web:search may call this."""
    # ... actual search logic ...
    return []

@requires_permission("docs:write")
def tool_write_document(agent_ctx, doc_id: str, content: str) -> None:
    """Write to a document. Only agents with docs:write may call this."""
    # ... actual write logic ...
    pass

@requires_permission("code:execute")
def tool_run_code(agent_ctx, code: str, language: str = "python") -> str:
