# agent_context.py — session-scoped role assignment
from dataclasses import dataclass
from pep import tool_web_search, tool_write_document, PermissionDenied

@dataclass
class AgentContext:
    agent_id: str
    role: str   # assigned at session start

# --- Session initialization ---
def start_research_session(session_id: str) -> AgentContext:
    return AgentContext(agent_id=f"agent-{session_id}", role="researcher")

def start_writing_session(session_id: str) -> AgentContext:
    return AgentContext(agent_id=f"agent-{session_id}", role="writer")

# --- Demonstrating enforcement ---
research_ctx = start_research_session("abc123")
writing_ctx = start_writing_session("def456")

# Researcher can search
results = tool_web_search(research_ctx, "RBAC for AI agents")  # OK

# Researcher cannot write
try:
    tool_write_document(research_ctx, "doc-1", "Hello world")
except PermissionDenied as e:
    print(f"Blocked: {e}")
    # "Agent 'agent-abc123' with role 'researcher' does not have permission 'docs:write'"

# Writer can write
tool_write_document(writing_ctx, "doc-1", "Hello world")  # OK

# pipeline.py — Multi-agent RBAC pipeline
import uuid
from agent_context import AgentContext
from pep import (
    tool_web_search, tool_write_document, PermissionDenied,
    requires_permission
)
from pdp import check_permission

@requires_permission("docs:read")
def tool_read_document(agent_ctx, doc_id: str) -> str:
    return f"<content of {doc_id}>"

@requires_permission("email:send")
def tool_send_email(agent_ctx, to: str, subject: str, body: str) -> None:
    print(f"Email sent to {to}: {subject}")

@requires_permission("cms:publish")
def tool_publish_cms(agent_ctx, doc_id: str) -> None:
    print(f"Published {doc_id} to CMS")


# Role catalog for this pipeline
PIPELINE_ROLES = {
    "research": "researcher",    # web:search, docs:read, knowledge_base:read
    "drafting": "writer",        # web:search, docs:read, docs:write, knowledge_base:read
    "review": "researcher",      # reader-equivalent: docs:read only
    "ops": "ops",                # code:execute, infra:deploy, infra:read + email:send, cms:publish
}


def run_pipeline(topic: str) -> None:
    session_id = str(uuid.uuid4())[:8]

    # Assign roles at pipeline initialization
    agents = {
        name: AgentContext(agent_id=f"{name}-{session_id}", role=role)
        for name, role in PIPELINE_ROLES.items()
    }

    # 1. Research phase
    research_results = tool_web_search(agents["research"], topic)
    print(f"Research complete: {len(research_results)} results")

    # 2. Drafting phase
    draft_id = f"draft-{session_id}"
    tool_write_document(agents["drafting"], draft_id, "Draft content here...")

    # 3. Review phase — ReviewAgent has read-only access
    draft_content = tool_read_document(agents["review"], draft_id)
    # ReviewAgent cannot write — any attempt is blocked:
    try:
        tool_write_document(agents["review"], draft_id, "Edited by reviewer")
    except PermissionDenied as e:
        print(f"Review agent correctly blocked from writing: {e}")

    # 4. Ops phase — publishes and notifies
    tool_publish_cms(agents["ops"], draft_id)
    tool_send_email(
        agents["ops"],
        to="team@example.com",
        subject="Content published",
        body=f"Draft {draft_id} is now live.",
    )


run_pipeline("Role-Based Access Control for AI agents")
